import { describe, it, expect } from "vitest";
import { processScenario } from "./scenario.js";

describe("MHPCO Claim Office - Scenario Processing", () => {
  // Base scenario shape
  it.todo("processes an empty scenario to empty results");

  // Quote: base premiums per main item type (first contract, 0 years)
  it.todo("quotes a single sword for a new customer");
  it.todo("quotes a single amulet for a new customer");
  it.todo("quotes a single staff for a new customer");
  it.todo("quotes a single potion for a new customer");

  // Quote: components
  it.todo("quotes a single component (rune) at 25 G base premium");
  it.todo("quotes three alike components as a 60 G block instead of 75 G");

  // Quote: risk surcharges
  it.todo("applies 50% cursed surcharge to a cursed item");
  it.todo("applies 30% high-enchantment surcharge to items with enchantment >= 5");

  // Quote: customer discounts/surcharges
  it.todo("applies 20% loyalty discount to a customer with >= 2 years");
  it.todo("applies 15% multi-contract discount on the second contract instead of first-insurance surcharge");

  // Quote: rounding in MHPCO's favor (round up)
  it.todo("rounds the premium up in MHPCO's favor");

  // Claim: basic mechanics
  it.todo("pays a claim minus the 100 G deductible");
  it.todo("pays zero when damage is at or below the deductible");
  it.todo("caps payout at twice the insurance sum");

  // Claim: special reimbursement rules
  it.todo("reimburses only 50% of damage for highly enchanted items (enchantment >= 8)");
  it.todo("fully reimburses damage to dragon-material items");

  // Claim: cap tracking across multiple claims
  it.todo("tracks remaining cap across multiple claims on the same policy");
});

