type Item = { type: string; subtype?: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: unknown; steps: QuoteStep[] };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  component: 25,
};

const COMPONENT_BLOCK_PREMIUM = 60;
const PROCESSING_FEE = 5;

const roundUp = (amount: number): number => Math.ceil(amount);

const itemsBaseTotal = (items: Item[]): number => {
  // 3 alike components form a special block at 60 G.
  if (
    items.length === 3 &&
    items.every((i) => i.type === "component" && i.subtype === items[0].subtype)
  ) {
    return COMPONENT_BLOCK_PREMIUM;
  }
  return items.reduce((sum, i) => sum + BASE_PREMIUM[i.type], 0);
};

const quotePremium = (step: QuoteStep): number => {
  const base = itemsBaseTotal(step.items);
  // First insurance: +10% (integer math avoids float rounding errors).
  const withFirstInsurance = (base * 11) / 10;
  return roundUp(withFirstInsurance) + PROCESSING_FEE;
};

export const processScenario = (input: unknown): unknown => {
  const { steps } = input as Scenario;
  return { results: steps.map((s) => ({ premium: quotePremium(s) })) };
};

